import React, { useState, useEffect } from 'react';
import axios from 'axios';

// Hierarchical Curriculum Structure: Unit -> Topic -> Subtopic
const CURRICULUM = {
  "Unit 1: Engineering Mechanics": {
    "Forces and Laws": ["Types of Forces", "Newton's Laws", "Parallelogram Law", "Principle of Transmissibility", "Lami's Theorem"],
    "Statics": ["Concurrent Forces", "Non-concurrent Forces", "Equilibrium Conditions", "Free Body Diagrams"],
    "Kinematics": ["Motion Types", "Velocity and Acceleration", "Projectile Motion", "Relative Motion"],
    "Kinetics": ["Newton's Second Law", "Work and Energy", "Impulse and Momentum", "Collision"],
    "Center of Gravity": ["Centroid", "Moment of Inertia", "Parallel Axis Theorem", "Perpendicular Axis Theorem"],
    "Friction": ["Laws of Friction", "Angle of Friction", "Wedge Friction", "Belt Friction"]
  },
  "Unit 2: Strength of Materials": {
    "Stresses and Strains": ["Normal Stress", "Shear Stress", "Strain Types", "Hooke's Law", "Elastic Constants"],
    "Shear Force and Bending Moment": ["SFD and BMD", "Cantilever Beams", "Simply Supported Beams", "Overhanging Beams"],
    "Bending and Shear Stresses": ["Theory of Simple Bending", "Section Modulus", "Shear Stress Distribution"],
    "Deflection of Beams": ["Double Integration Method", "Macaulay's Method", "Moment Area Method", "Conjugate Beam Method"],
    "Torsion": ["Torsion Formula", "Power Transmission", "Helical Springs"],
    "Columns": ["Euler's Theory", "Rankine's Formula", "Slenderness Ratio", "Effective Length"]
  },
  "Unit 3: Structural Analysis": {
    "Trusses": ["Method of Joints", "Method of Sections", "Zero Force Members"],
    "Arches": ["Three-hinged Arch", "Two-hinged Arch", "Tied Arch"],
    "Cables": ["Cable Subjected to UDL", "Cable Subjected to Point Load", "Suspension Bridge"],
    "Influence Lines": ["Muller-Breslau Principle", "Influence Line for Beams", "Influence Line for Trusses"],
    "Indeterminate Structures": ["Force Method", "Displacement Method", "Moment Distribution Method"]
  },
  "Unit 4: Building Materials": {
    "Cement": ["Types of Cement", "Manufacturing Process", "Properties", "Tests on Cement"],
    "Aggregates": ["Classification", "Properties", "Testing", "Gradation"],
    "Concrete": ["Mix Design", "Properties", "Tests", "Special Concretes"],
    "Steel": ["Types of Steel", "Properties", "Heat Treatment", "Corrosion"],
    "Timber": ["Classification", "Defects", "Preservation", "Products"],
    "Bricks and Masonry": ["Brick Manufacturing", "Brick Properties", "Masonry Types", "Masonry Design"]
  },
  "Unit 5: Concrete Structures": {
    "Working Stress Method": ["Design Philosophy", "Modular Ratio", "Critical Sections"],
    "Limit State Method": ["Partial Safety Factors", "Limit States", "Serviceability"],
    "Slabs": ["One-way Slab", "Two-way Slab", "Flat Slab", "Design Procedure"],
    "Beams": ["Singly Reinforced", "Doubly Reinforced", "T-Beam", "Shear Design"],
    "Columns": ["Short Columns", "Long Columns", "Combined Footing", "Pile Cap"],
    "Prestressed Concrete": ["Pre-tensioning", "Post-tensioning", "Losses", "Design Principles"]
  },
  "Unit 6: Steel Structures": {
    "Connections": ["Bolted Connections", "Welded Connections", "Design of Joints"],
    "Tension Members": ["Design Strength", "Slenderness Ratio", "Lug Angles"],
    "Compression Members": ["Column Buckling", "Built-up Columns", "Lacing and Battening"],
    "Beams": ["Laterally Supported Beams", "Laterally Unsupported Beams", "Plate Girders"],
    "Roof Trusses": ["Types of Trusses", "Load Calculation", "Design Procedure"]
  },
  "Unit 7: Soil Mechanics": {
    "Properties of Soils": ["Phase Relations", "Grain Size Distribution", "Atterberg Limits", "Classification"],
    "Permeability": ["Darcy's Law", "Coefficient of Permeability", "Well Hydraulics"],
    "Compaction": ["Compaction Tests", "Factors Affecting Compaction", "Field Compaction Control"],
    "Consolidation": ["Compression Index", "Coefficient of Consolidation", "Settlement Calculation"],
    "Shear Strength": ["Mohr-Coulomb Theory", "Direct Shear Test", "Triaxial Test", "UU, CU, CD Tests"],
    "Earth Pressure": ["Rankine's Theory", "Coulomb's Theory", "Retaining Walls", "Sheet Piles"]
  },
  "Unit 8: Foundation Engineering": {
    "Site Investigation": ["Methods", "Soil Sampling", "Borehole Logs", "Geophysical Methods"],
    "Shallow Foundations": ["Bearing Capacity", "Settlement Analysis", "Combined Footings", "Raft Foundation"],
    "Deep Foundations": ["Pile Types", "Pile Capacity", "Pile Groups", "Well Foundations"],
    "Ground Improvement": ["Compaction", "Grouting", "Soil Stabilization", "Reinforced Earth"]
  },
  "Unit 9: Hydraulics": {
    "Fluid Properties": ["Viscosity", "Surface Tension", "Compressibility", "Vapor Pressure"],
    "Fluid Statics": ["Pressure Measurement", "Hydrostatic Forces", "Buoyancy", "Stability of Floating Bodies"],
    "Fluid Kinematics": ["Streamlines", "Continuity Equation", "Velocity Potential", "Stream Function"],
    "Fluid Dynamics": ["Bernoulli's Equation", "Momentum Equation", "Flow Measurement"],
    "Pipe Flow": ["Major Losses", "Minor Losses", "Pipe Networks", "Water Hammer"],
    "Open Channel Flow": ["Uniform Flow", "Manning's Formula", "Specific Energy", "Hydraulic Jump"]
  },
  "Unit 10: Water Resources": {
    "Hydrology": ["Precipitation", "Runoff", "Hydrograph", "Unit Hydrograph", "Flood Estimation"],
    "Irrigation": ["Water Requirements", "Canal Design", "Canal Structures", "Water Logging"],
    "Dams": ["Gravity Dam", "Earthen Dam", "Spillways", "Energy Dissipators"]
  }
};

// Define units outside component to avoid recreating on each render
const UNITS = Object.keys(CURRICULUM);
const DEFAULT_UNIT = UNITS[0];
const DEFAULT_TOPIC = Object.keys(CURRICULUM[DEFAULT_UNIT])[0];
const DEFAULT_SUBTOPIC = CURRICULUM[DEFAULT_UNIT][DEFAULT_TOPIC][0];

function AIGenerator() {
  const [selectedUnit, setSelectedUnit] = useState(DEFAULT_UNIT);
  const [selectedTopic, setSelectedTopic] = useState(DEFAULT_TOPIC);
  const [selectedSubtopic, setSelectedSubtopic] = useState(DEFAULT_SUBTOPIC);
  const [notebookUrl, setNotebookUrl] = useState('');
  const [pastedContent, setPastedContent] = useState('');
  const [batch, setBatch] = useState([]);
  const [loading, setLoading] = useState(false);
  const [questionCount, setQuestionCount] = useState(0);
  const [message, setMessage] = useState('');

  // Get topics for selected unit
  const topics = selectedUnit ? Object.keys(CURRICULUM[selectedUnit]) : [];

  // Get subtopics for selected topic
  const subtopics = selectedUnit && selectedTopic ? CURRICULUM[selectedUnit][selectedTopic] : [];

  useEffect(() => {
    // Reset topic and subtopic when unit changes
    if (selectedUnit) {
      const newTopics = Object.keys(CURRICULUM[selectedUnit]);
      setSelectedTopic(newTopics[0]);
      setSelectedSubtopic(CURRICULUM[selectedUnit][newTopics[0]][0]);
    }
  }, [selectedUnit]);

  useEffect(() => {
    // Reset subtopic when topic changes
    if (selectedUnit && selectedTopic) {
      setSelectedSubtopic(CURRICULUM[selectedUnit][selectedTopic][0]);
    }
  }, [selectedTopic]);

  useEffect(() => {
    fetchQuestionCount();
  }, [selectedSubtopic]);

  const fetchQuestionCount = async () => {
    try {
      const response = await axios.get(`/api/questions/stats/count?subtopic=${encodeURIComponent(selectedSubtopic)}`);
      setQuestionCount(response.data.count);
    } catch (error) {
      console.error('Error fetching count:', error);
    }
  };

  const handleQuickExtract = async () => {
    if (!pastedContent) {
      alert('Please paste content first!');
      return;
    }

    // Calculate how many more questions needed
    const remaining = Math.max(0, 25 - questionCount);
    if (remaining === 0) {
      alert('This subtopic already has 25 questions!');
      return;
    }

    setLoading(true);
    try {
      console.log('Sending content length:', pastedContent.length);
      const response = await axios.post('/api/ai/extract', {
        textContent: pastedContent,
        unit: selectedUnit,
        topic: selectedTopic,
        subtopic: selectedSubtopic,
        maxQuestions: remaining
      });

      console.log('Extracted questions:', response.data.questions.length);
      const questions = response.data.questions.map((q, idx) => ({
        ...q,
        id: Date.now() + idx,
        status: 'PENDING'
      }));
      setBatch(questions);

      if (questions.length === 0) {
        setMessage('No questions found in the pasted content. Make sure your questions are numbered (1., 2., etc.) and have options (a, b, c, d).');
      } else {
        setMessage(`Extracted ${questions.length} question${questions.length > 1 ? 's' : ''}. Review and save them.`);
      }
    } catch (error) {
      alert('Extraction failed: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const addManualQuestion = () => {
    setBatch([{
      id: Date.now(),
      question: 'New Concept Question',
      options: { a: '', b: '', c: '', d: '' },
      correct_answer: 'a',
      explanation: '',
      type: 'Theory-based MCQ',
      unit: selectedUnit,
      topic: selectedTopic,
      subtopic: selectedSubtopic,
      status: 'APPROVED'
    }, ...batch]);
  };

  const updateQuestion = (id, field, value) => {
    setBatch(batch.map(q => q.id === id ? { ...q, [field]: value } : q));
  };

  const updateOption = (id, key, value) => {
    setBatch(batch.map(q =>
      q.id === id ? { ...q, options: { ...q.options, [key]: value } } : q
    ));
  };

  const handleImageUpload = async (e, id, type, optionKey = null) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('image', file);

    try {
      const response = await axios.post('/api/questions/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      const imageUrl = response.data.imageUrl;

      setBatch(batch.map(q => {
        if (q.id !== id) return q;

        if (type === 'question') {
          return { ...q, questionImage: imageUrl };
        } else if (type === 'explanation') {
          return { ...q, explanationImage: imageUrl };
        } else if (type === 'option' && optionKey) {
          const newOptionImages = { ...(q.optionImages || { a: null, b: null, c: null, d: null }) };
          newOptionImages[optionKey] = imageUrl;
          return { ...q, optionImages: newOptionImages };
        }
        return q;
      }));
    } catch (error) {
      alert('Image upload failed: ' + error.message);
    }
  };

  const removeImage = (id, type, optionKey = null) => {
    setBatch(batch.map(q => {
      if (q.id !== id) return q;

      if (type === 'question') {
        return { ...q, questionImage: null };
      } else if (type === 'explanation') {
        return { ...q, explanationImage: null };
      } else if (type === 'option' && optionKey) {
        const newOptionImages = { ...(q.optionImages || { a: null, b: null, c: null, d: null }) };
        newOptionImages[optionKey] = null;
        return { ...q, optionImages: newOptionImages };
      }
      return q;
    }));
  };

  const getImagePreview = (imageUrl) => {
    if (!imageUrl) return null;
    return imageUrl.startsWith('http') ? imageUrl : `http://localhost:5000${imageUrl}`;
  };

  const saveSingleQuestion = async (id) => {
    const q = batch.find(item => item.id === id);
    if (!q) return;

    setLoading(true);
    try {
      // Convert to new schema format
      const answerMap = { 'a': 0, 'b': 1, 'c': 2, 'd': 3 };
      const questionData = {
        unit: q.unit || selectedUnit,
        topic: q.topic || selectedTopic,
        subtopic: q.subtopic || selectedSubtopic,
        type: q.type || 'Theory-based MCQ',
        question: q.question,
        questionImage: q.questionImage || null,
        options: q.options,
        optionImages: q.optionImages || { a: null, b: null, c: null, d: null },
        correctAnswer: answerMap[q.correct_answer] || 0,
        explanation: q.explanation || '',
        explanationImage: q.explanationImage || null,
        status: 'accepted',
        is_published: false
      };

      await axios.post('/api/questions', questionData);

      // Remove from batch after successful save
      setBatch(batch.filter(item => item.id !== id));
      setMessage('Question saved successfully!');
      fetchQuestionCount();
    } catch (error) {
      setMessage('Error saving question: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const setStatus = (id, status) => {
    if (status === 'APPROVED') {
      saveSingleQuestion(id);
    } else {
      setBatch(batch.map(q => q.id === id ? { ...q, status } : q));
    }
  };

  const deleteQuestion = (id) => {
    setBatch(batch.filter(q => q.id !== id));
  };

  const clearBatch = () => {
    setBatch([]);
  };

  const saveAll = async () => {
    const toSave = batch.filter(q => q.status !== 'REJECTED');
    if (toSave.length === 0) {
      alert('No questions to save!');
      return;
    }

    setLoading(true);
    try {
      const answerMap = { 'a': 0, 'b': 1, 'c': 2, 'd': 3 };

      for (const q of toSave) {
        const questionData = {
          unit: q.unit || selectedUnit,
          topic: q.topic || selectedTopic,
          subtopic: q.subtopic || selectedSubtopic,
          type: q.type || 'Theory-based MCQ',
          question: q.question,
          questionImage: q.questionImage || null,
          options: q.options,
          optionImages: q.optionImages || { a: null, b: null, c: null, d: null },
          correctAnswer: answerMap[q.correct_answer] || 0,
          explanation: q.explanation || '',
          explanationImage: q.explanationImage || null,
          status: 'accepted',
          is_published: false
        };
        await axios.post('/api/questions', questionData);
      }
      setMessage(`Successfully saved ${toSave.length} questions!`);
      setBatch([]);
      fetchQuestionCount();
    } catch (error) {
      setMessage('Error saving: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const progressPct = Math.min(100, (questionCount / 25) * 100);

  return (
    <div className="tab-content">
      <h2>Question Extractor</h2>

      <div className="info-box">
        Paste content to extract questions automatically. Review and save individual questions or approve all at once.
      </div>

      <div className="form-row">
        <div className="form-group">
          <label>Select Unit</label>
          <select value={selectedUnit} onChange={(e) => setSelectedUnit(e.target.value)}>
            {units.map(u => <option key={u} value={u}>{u}</option>)}
          </select>
        </div>
        <div className="form-group">
          <label>Select Topic</label>
          <select value={selectedTopic} onChange={(e) => setSelectedTopic(e.target.value)}>
            {topics.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>
        <div className="form-group">
          <label>Select Subtopic</label>
          <select value={selectedSubtopic} onChange={(e) => setSelectedSubtopic(e.target.value)}>
            {subtopics.map(st => <option key={st} value={st}>{st}</option>)}
          </select>
        </div>
      </div>

      <div className="progress-container">
        <div className="progress-header">
          <span className="progress-title">Live Subtopic Pulse: {selectedSubtopic}</span>
          <span className={`progress-count ${questionCount >= 25 ? 'complete' : ''}`}>
            {questionCount} / 25 Questions Verified
          </span>
        </div>
        <div className="progress-bar">
          <div
            className={`progress-fill ${questionCount >= 25 ? 'complete' : ''}`}
            style={{ width: `${progressPct}%` }}
          />
        </div>
        {questionCount >= 25 ? (
          <div style={{ color: '#008000', marginTop: '8px', fontWeight: 700 }}>Subtopic Complete!</div>
        ) : (
          <div style={{ color: '#000000', marginTop: '8px' }}>Add {25 - questionCount} more to unlock for students.</div>
        )}
      </div>

      <div className="form-group">
        <label>Paste Notebook LLM Source URL</label>
        <input 
          type="text" 
          value={notebookUrl} 
          onChange={(e) => setNotebookUrl(e.target.value)}
          placeholder="https://notebooklm.google.com/..."
        />
      </div>

      <div className="form-group">
        <label>Paste Questions Content</label>
        <textarea
          value={pastedContent}
          onChange={(e) => setPastedContent(e.target.value)}
          rows={10}
          placeholder={`Paste your questions here in this format:

1. What is the capital of France?
a) London
b) Paris
c) Berlin
d) Madrid
Answer: b
Explanation: Paris is the capital of France.

2. What is 2+2?
a) 3
b) 4
c) 5
d) 6
Answer: b`}
        />
        <small style={{ color: '#000000', display: 'block', marginTop: '8px' }}>
          Format: Numbered questions with options (a, b, c, d) and optional Answer/Explanation
        </small>
      </div>

      <div className="action-row">
        <button
          className="btn-primary"
          onClick={handleQuickExtract}
          disabled={loading}
        >
          {loading ? 'Extracting...' : 'Extract Questions'}
        </button>
      </div>

      {message && (
        <div className={message.includes('Error') ? 'error-message' : 'success-message'}>
          {message}
        </div>
      )}

      {batch.length > 0 && (
        <>
          <div className="action-row" style={{ marginTop: '24px' }}>
            <button className="btn-secondary" onClick={addManualQuestion}>
              Add Manual Question
            </button>
            <button className="btn-primary" onClick={saveAll} disabled={loading}>
              {loading ? 'Saving...' : 'Approve & Save Everything'}
            </button>
            <button className="btn-danger" onClick={clearBatch}>
              Clear Review List
            </button>
          </div>

          <h3 style={{ marginTop: '24px', marginBottom: '16px' }}>Review Mode & Question Management</h3>

          {batch.map((q, idx) => (
            <div key={q.id} className={`question-card ${q.status.toLowerCase()}`}>
              <div className="question-header">
                <h3>Question {idx + 1}</h3>
                <span className={`status-badge ${q.status.toLowerCase()}`}>{q.status}</span>
              </div>
              
              <div className="question-topic">[{q.subcategory}]</div>
              
              <div className="edit-form">
                {/* Question Section */}
                <div className="section">
                  <h4>Question</h4>
                  <div className="form-group">
                    <label>Question Text</label>
                    <textarea
                      value={q.question}
                      onChange={(e) => updateQuestion(q.id, 'question', e.target.value)}
                      rows={3}
                    />
                  </div>
                  <div className="form-group">
                    <label>Question Image (Optional)</label>
                    <input
                      type="file"
                      accept="image/*"
                      onChange={(e) => handleImageUpload(e, q.id, 'question')}
                    />
                    {q.questionImage && (
                      <div className="image-preview-container">
                        <img
                          src={getImagePreview(q.questionImage)}
                          alt="Question"
                          className="image-preview"
                        />
                        <button type="button" className="btn-remove-image" onClick={() => removeImage(q.id, 'question')}>
                          Remove
                        </button>
                      </div>
                    )}
                  </div>
                </div>

                {/* Options Section */}
                <div className="section">
                  <h4>Options</h4>
                  {['a', 'b', 'c', 'd'].map((opt) => (
                    <div key={opt} className="option-row">
                      <div className="option-input-group">
                        <div className="form-group option-text">
                          <label>Option {opt.toUpperCase()}</label>
                          <input
                            value={q.options[opt]}
                            onChange={(e) => updateOption(q.id, opt, e.target.value)}
                          />
                        </div>
                        <div className="form-group option-image">
                          <label>Image</label>
                          <input
                            type="file"
                            accept="image/*"
                            onChange={(e) => handleImageUpload(e, q.id, 'option', opt)}
                          />
                          {q.optionImages?.[opt] && (
                            <div className="image-preview-small">
                              <img
                                src={getImagePreview(q.optionImages[opt])}
                                alt={`Option ${opt.toUpperCase()}`}
                              />
                              <button type="button" className="btn-remove-small" onClick={() => removeImage(q.id, 'option', opt)}>
                                x
                              </button>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="form-group">
                  <label>Correct Answer</label>
                  <select
                    value={q.correct_answer}
                    onChange={(e) => updateQuestion(q.id, 'correct_answer', e.target.value)}
                  >
                    <option value="a">A</option>
                    <option value="b">B</option>
                    <option value="c">C</option>
                    <option value="d">D</option>
                  </select>
                </div>

                {/* Explanation Section */}
                <div className="section">
                  <h4>Explanation</h4>
                  <div className="form-group">
                    <label>Explanation Text</label>
                    <textarea
                      value={q.explanation}
                      onChange={(e) => updateQuestion(q.id, 'explanation', e.target.value)}
                      rows={4}
                      placeholder="Enter detailed explanation here..."
                    />
                  </div>
                  <div className="form-group">
                    <label>Explanation Image (Optional)</label>
                    <input
                      type="file"
                      accept="image/*"
                      onChange={(e) => handleImageUpload(e, q.id, 'explanation')}
                    />
                    {q.explanationImage && (
                      <div className="image-preview-container">
                        <img
                          src={getImagePreview(q.explanationImage)}
                          alt="Explanation"
                          className="image-preview"
                        />
                        <button type="button" className="btn-remove-image" onClick={() => removeImage(q.id, 'explanation')}>
                          Remove
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>

              <div className="card-actions">
                <button className="btn-primary" onClick={() => setStatus(q.id, 'APPROVED')}>
                  Save & Accept
                </button>
                <button className="btn-danger" onClick={() => setStatus(q.id, 'REJECTED')}>
                  Reject
                </button>
                <button className="btn-danger" onClick={() => deleteQuestion(q.id)}>
                  Delete
                </button>
              </div>
            </div>
          ))}
        </>
      )}
    </div>
  );
}

export default AIGenerator;
